406	// Heartbeat checks if the server has started and is responsive; if yes, it
407	// returns nil, otherwise an error.
408	func (c *Client) Heartbeat(ctx context.Context) error {
409		if err := c.do(ctx, http.MethodHead, "/", nil, nil); err != nil {
410			return err
411		}
412		return nil
413	}
