439	// Version returns the Ollama server version as a string.
440	func (c *Client) Version(ctx context.Context) (string, error) {
441		var version struct {
442			Version string `json:"version"`
443		}
444	
445		if err := c.do(ctx, http.MethodGet, "/api/version", nil, &version); err != nil {
446			return "", err
